function Badge({sf2, t}) {
  const map = {
    null:       {color:C.grayText,bg:"#f1f5f9",label:t.brouillon},
    en_attente: {color:"#92400e", bg:"#fef3c7", label:t.att_validation},
    validee:    {color:C.success, bg:"#dcfce7", label:t.validee},
    modifiee:   {color:C.danger,  bg:"#fee2e2", label:t.modifiee},
  };
  const icons = {null:"📝",en_attente:"⏳",validee:"✅",modifiee:"⚠️"};
  const st = map[sf2]||map[null];
  return <span style={sf.pill(st.color,st.bg)}>{icons[sf2]||"📝"} {st.label}</span>;
}

// ─── LOGIN ────────────────────────────────────────────────────────────────────
function PageLogin({onLogin}) {
  const [code,setCode]=useState(""); const [err,setErr]=useState(""); const [lang,setLang]=useState("fr");
  const t=T[lang]; const handle=()=>{const r=CODES[code.trim().toUpperCase()];if(r)onLogin(r,lang);else setErr(t.code_incorrect);};
  return (
    <div style={{minHeight:"100vh",background:C.navy,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{position:"absolute",top:16,right:16,display:"flex",gap:6}}>
        {["fr","en","tr"].map(l=><button key={l} onClick={()=>setLang(l)} style={{background:lang===l?C.accent:"rgba(255,255,255,0.12)",border:"none",color:lang===l?C.navy:"rgba(255,255,255,0.8)",cursor:"pointer",padding:"5px 11px",borderRadius:20,fontSize:12,fontWeight:700,fontFamily:"sans-serif"}}>{{fr:"🇫🇷 FR",en:"🇬🇧 EN",tr:"🇹🇷 TR"}[l]}</button>)}
      </div>
      <div style={{background:C.white,borderRadius:20,padding:"44px 40px",width:"100%",maxWidth:400,boxShadow:"0 24px 80px rgba(0,0,0,0.4)"}}>
        <div style={{textAlign:"center",marginBottom:36}}>
          <img src={DFDS_LOGO} alt="DFDS" style={{height:50,objectFit:"contain",marginBottom:20,display:"block",margin:"0 auto 20px"}}/>
          <div style={{fontSize:11,color:C.grayText,fontFamily:"sans-serif",letterSpacing:"0.14em",textTransform:"uppercase",fontWeight:700}}>DEPOT MANAGER</div>
          <div style={{fontSize:10,color:C.grayMid,fontFamily:"sans-serif",marginTop:4,letterSpacing:"0.08em",textTransform:"uppercase"}}>{t.acces_securise}</div>
        </div>
        <label style={{...sf.lbl,textAlign:"center",display:"block",marginBottom:8}}>{t.code_acces}</label>
        <input style={{...sf.inp,fontSize:18,letterSpacing:"0.15em",textAlign:"center",borderWidth:2,marginBottom:12}} type="password" placeholder="••••••••" value={code} onChange={e=>setCode(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handle()} autoFocus/>
        {err&&<div style={{color:C.danger,fontFamily:"sans-serif",fontSize:13,marginBottom:12,textAlign:"center",background:"#fee2e2",padding:"8px",borderRadius:8}}>{err}</div>}
        <button style={{...sf.btn("primary"),width:"100%",padding:"14px",fontSize:15,borderRadius:10}} onClick={handle}>{t.acceder} →</button>
        <div style={{marginTop:20,fontFamily:"sans-serif",fontSize:11,color:C.grayMid,textAlign:"center"}}>{t.personnel_dfds}</div>
      </div>
    </div>
  );
}

// ─── FORM DOSSIER ─────────────────────────────────────────────────────────────
function FormDossier({clients,tarifs,dossierInitial,onSave,onCancel,t}) {
  const editing=!!dossierInitial;
  const [form,setForm]=useState(dossierInitial?{client:dossierInitial.client,invoiceRef:dossierInitial.invoiceRef||"",notes:dossierInitial.notes||"",palettisation:dossierInitial.palettisation||0,depotage:dossierInitial.depotage||0}:{client:clients[0]?.nom||"",invoiceRef:"",notes:"",palettisation:0,depotage:0});
  const [mouvements,setMouvements]=useState(dossierInitial?.mouvements||[]);
  const [fraisSupp,setFraisSupp]=useState(dossierInitial?.fraisSupp||[]);
  const [mvt,setMvt]=useState({type:"entree",date:today(),palettes:1,provenance:"",transporteur:"",poids:""});
  const [frais,setFrais]=useState({desc:"",type:"libre",montant:0,qty:1,pu:0});
  const [photos,setPhotos]=useState(dossierInitial?.photos||[]);
  const photoRef=useRef(null);
  const addPhotos=(files)=>{Array.from(files).forEach(file=>{const reader=new FileReader();reader.onload=(e)=>setPhotos(ph=>[...ph,{id:Date.now()+Math.random(),name:file.name,data:e.target.result}]);reader.readAsDataURL(file);});};
  const [erreur,setErreur]=useState("");
  const addMvt=()=>{if(mvt.palettes<1)return;setMouvements(m=>[...m,{...mvt,id:Date.now()}]);setMvt(v=>({...v,palettes:1,provenance:"",transporteur:"",poids:""}));};
  const addFrais=()=>{if(!frais.desc)return;const total=frais.type==="libre"?+frais.montant:+frais.qty*+frais.pu;setFraisSupp(f=>[...f,{...frais,total,id:Date.now()}]);setFrais({desc:"",type:"libre",montant:0,qty:1,pu:0});};
  const handleSave=()=>{
    if(!mouvements.length){setErreur(t.erreur_mouvement);return;}
    const e=mouvements.filter(m=>m.type==="entree").reduce((s,m)=>s+m.palettes,0);
    const so=mouvements.filter(m=>m.type==="sortie").reduce((s,m)=>s+m.palettes,0);
    const clientObj=clients.find(c=>c.nom===form.client)||{tva:true};
    const wasValidee=dossierInitial?.statutFacture==="validee";
    const dossierBase={...(dossierInitial||{id:Date.now()}),...form,mouvements,fraisSupp,
      dateCreation:dossierInitial?.dateCreation||today(),statut:so>=e?"clos":"ouvert",
      tvaClient:clientObj.tva,statutFacture:wasValidee?"modifiee":(dossierInitial?.statutFacture||null)};
    const lignesSnap=genFacture({...dossierBase,lignesSnap:null},tarifs).lignes;
    onSave({...dossierBase,lignesSnap,photos});
  };
  const clientObj=clients.find(c=>c.nom===form.client);
  return (
    <div>
      {dossierInitial?.statutFacture==="validee"&&<div style={{background:"#fee2e2",border:"1.5px solid "+C.danger,borderRadius:10,padding:"12px 16px",marginBottom:16,fontFamily:"sans-serif",fontSize:13,color:C.danger}}>{t.facture_validee_warning}</div>}
      <div style={sf.card}>
        <div style={sf.sec}>{t.infos_client}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(180px,1fr))",gap:16}}>
          <div>
            <label style={sf.lbl}>{t.client}</label>
            <select style={sf.sel} value={form.client} onChange={e=>setForm(f=>({...f,client:e.target.value}))}>
              {clients.map(c=><option key={c.nom} value={c.nom}>{c.nom}{c.numero?" ("+c.numero+")":""}{!c.tva?" – HT":""}</option>)}
            </select>
            {clientObj&&!clientObj.tva&&<div style={{fontSize:11,color:"#92400e",marginTop:5,background:"#fef9c3",padding:"4px 8px",borderRadius:6,fontFamily:"sans-serif"}}>⚠️ HT</div>}
          </div>
          <div><label style={sf.lbl}>{t.invoice_ref}</label><input style={sf.inp} placeholder="ex: ARS26OZ18248M" value={form.invoiceRef} onChange={e=>setForm(f=>({...f,invoiceRef:e.target.value}))}/></div>
          <div><label style={sf.lbl}>{t.notes_internes}</label><input style={sf.inp} placeholder={t.notes_placeholder} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/></div>
        </div>
      </div>
      <div style={sf.card}>
        <div style={sf.sec}>{t.mouvements}</div>
        <div style={{background:C.offWhite,border:"1.5px solid "+C.border,borderRadius:10,padding:16,marginBottom:14}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:12,alignItems:"end"}}>
            <div><label style={sf.lbl}>{t.type}</label>
              <select style={sf.sel} value={mvt.type} onChange={e=>setMvt(v=>({...v,type:e.target.value}))}>
                <option value="entree">↓ {t.entree}</option><option value="sortie">↑ {t.sortie}</option>
              </select>
            </div>
            <div><label style={sf.lbl}>{t.date}</label><input style={sf.inp} type="date" value={mvt.date} onChange={e=>setMvt(v=>({...v,date:e.target.value}))}/></div>
            <div><label style={sf.lbl}>{t.palettes}</label><input style={sf.inp} type="number" min={1} value={mvt.palettes} onChange={e=>setMvt(v=>({...v,palettes:+e.target.value}))}/></div>
            <div><label style={sf.lbl}>{t.provenance_bl}</label><input style={sf.inp} placeholder="BL-001..." value={mvt.provenance} onChange={e=>setMvt(v=>({...v,provenance:e.target.value}))}/></div>
            <div><label style={sf.lbl}>{t.transporteur_plaque}</label><input style={sf.inp} placeholder="AB-123-CD" value={mvt.transporteur} onChange={e=>setMvt(v=>({...v,transporteur:e.target.value}))}/></div>
            <div><label style={sf.lbl}>{t.poids_kg}</label><input style={sf.inp} type="number" min={0} placeholder="1250" value={mvt.poids} onChange={e=>setMvt(v=>({...v,poids:e.target.value}))}/></div>
            <div style={{display:"flex",alignItems:"flex-end"}}><button style={{...sf.btn("accent"),width:"100%"}} onClick={addMvt}>{t.ajouter}</button></div>
          </div>
        </div>
        {mouvements.length===0?<div style={{textAlign:"center",padding:"20px 0",color:C.grayText,fontFamily:"sans-serif",fontSize:13}}>{t.aucun_mouvement}</div>
          :mouvements.map((m,i)=>(
            <div key={m.id} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 14px",borderRadius:8,marginBottom:6,background:m.type==="entree"?"#eff6ff":"#fdf4ff",border:"1px solid "+(m.type==="entree"?"#bfdbfe":"#e9d5ff")}}>
              <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
                <span style={sf.tag(m.type)}>{m.type==="entree"?"↓":"↑"} {m.palettes} pal.</span>
                <span style={{fontFamily:"sans-serif",fontSize:12,color:C.grayText}}>{m.date}</span>
                {m.poids&&<span style={{fontFamily:"sans-serif",fontSize:12,color:C.grayText}}>⚖️ {m.poids}kg</span>}
                {m.transporteur&&<span style={{fontFamily:"sans-serif",fontSize:12,color:C.grayText}}>🚛 {m.transporteur}</span>}
                {m.provenance&&<span style={{fontFamily:"sans-serif",fontSize:12,color:C.grayText}}>· {m.provenance}</span>}
                {m.transporteur&&<span style={{fontFamily:"sans-serif",fontSize:12,color:C.grayText}}>🚛 {m.transporteur}</span>}
                {m.poids&&<span style={{fontFamily:"sans-serif",fontSize:12,color:C.grayText}}>⚖️ {m.poids} kg</span>}
              </div>
              <button onClick={()=>setMouvements(ms=>ms.filter((_,j)=>j!==i))} style={{background:"none",border:"none",color:C.danger,cursor:"pointer",fontSize:20}}>✕</button>
            </div>
          ))}
        {erreur&&<div style={{color:C.danger,fontFamily:"sans-serif",fontSize:13,marginTop:8}}>{erreur}</div>}
      </div>
      <div style={sf.card}>
        <div style={sf.sec}>{t.prestations_supp}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(200px,1fr))",gap:16}}>
          <div><label style={sf.lbl}>{t.palettisation}</label><input style={sf.inp} type="number" min={0} value={form.palettisation} onChange={e=>setForm(f=>({...f,palettisation:+e.target.value}))}/></div>
          <div><label style={sf.lbl}>{t.depotage}</label><input style={sf.inp} type="number" min={0} value={form.depotage} onChange={e=>setForm(f=>({...f,depotage:+e.target.value}))}/></div>
        </div>
      </div>
      <div style={sf.card}>
        <div style={sf.sec}>{t.frais_supp}</div>
        <div style={{background:C.offWhite,border:"1.5px solid "+C.border,borderRadius:10,padding:16,marginBottom:14}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(120px,1fr))",gap:12,alignItems:"end"}}>
            <div><label style={sf.lbl}>{t.description}</label><input style={sf.inp} placeholder="ex: Manutention spéciale" value={frais.desc} onChange={e=>setFrais(f=>({...f,desc:e.target.value}))}/></div>
            <div><label style={sf.lbl}>Type</label><select style={sf.sel} value={frais.type} onChange={e=>setFrais(f=>({...f,type:e.target.value}))}><option value="libre">{t.montant_libre}</option><option value="qpu">{t.qte_pu}</option></select></div>
            {frais.type==="libre"?<div style={{gridColumn:"span 2"}}><label style={sf.lbl}>{t.montant_ht}</label><input style={sf.inp} type="number" min={0} step="0.01" value={frais.montant} onChange={e=>setFrais(f=>({...f,montant:+e.target.value}))}/></div>
              :<><div><label style={sf.lbl}>{t.quantite}</label><input style={sf.inp} type="number" min={1} value={frais.qty} onChange={e=>setFrais(f=>({...f,qty:+e.target.value}))}/></div><div><label style={sf.lbl}>{t.pu_ht}</label><input style={sf.inp} type="number" min={0} step="0.01" value={frais.pu} onChange={e=>setFrais(f=>({...f,pu:+e.target.value}))}/></div></>}
            <div style={{display:"flex",alignItems:"flex-end"}}><button style={{...sf.btn("accent"),whiteSpace:"nowrap"}} onClick={addFrais}>{t.ajouter}</button></div>
          </div>
        </div>
        {fraisSupp.length===0?<div style={{textAlign:"center",padding:12,color:C.grayText,fontFamily:"sans-serif",fontSize:13}}>{t.aucun_frais}</div>
          :fraisSupp.map((f,i)=>(
            <div key={f.id} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 14px",borderRadius:8,marginBottom:6,background:C.accentLight,border:"1px solid #f0d090"}}>
              <div style={{fontFamily:"sans-serif",fontSize:13}}><span style={{fontWeight:600}}>{f.desc}</span><span style={{color:C.grayText,marginLeft:8}}>{f.type==="qpu"?f.qty+" × "+f.pu+" €":""}</span></div>
              <div style={{display:"flex",alignItems:"center",gap:12}}><span style={{fontWeight:700,color:C.accent,fontFamily:"sans-serif"}}>{(f.total||f.montant||0).toFixed(2)} € HT</span><button onClick={()=>setFraisSupp(fs=>fs.filter((_,j)=>j!==i))} style={{background:"none",border:"none",color:C.danger,cursor:"pointer",fontSize:20}}>✕</button></div>
            </div>
          ))}
      </div>
      <div style={sf.card}>
        <div style={sf.sec}>📷 Photos des palettes</div>
        <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:10}}> 
          {photos.map((p,i)=>(
            <div key={p.id} style={{position:"relative"}}>
              <img src={p.data} alt={p.name} style={{width:90,height:90,objectFit:"cover",borderRadius:8,border:"1.5px solid "+C.border}}/>
              <button onClick={()=>setPhotos(ph=>ph.filter((_,j)=>j!==i))} style={{position:"absolute",top:-6,right:-6,background:C.danger,color:"#fff",border:"none",borderRadius:"50%",width:20,height:20,cursor:"pointer",fontSize:13,fontWeight:700}}>✕</button>
            </div>
          ))}
          <button onClick={()=>photoRef.current?.click()} style={{width:90,height:90,border:"2px dashed "+C.border,borderRadius:8,background:C.offWhite,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,color:C.grayText,fontFamily:"sans-serif",fontSize:11,fontWeight:600}}>
            <span style={{fontSize:24}}>📷</span>
            <span>Ajouter</span>
          </button>
        </div>
        <input ref={photoRef} type="file" accept="image/*" capture="environment" multiple style={{display:"none"}} onChange={e=>addPhotos(e.target.files)}/>
      </div>
      <div style={{display:"flex",gap:10,justifyContent:"flex-end",paddingBottom:32}}>
        {onCancel&&<button style={sf.btn("ghost")} onClick={onCancel}>{t.annuler}</button>}
        <button style={{...sf.btn("primary"),padding:"12px 32px",fontSize:14}} onClick={handleSave}>💾 {editing?t.enregistrer_modif:t.creer_dossier}</button>
      </div>
    </div>
  );
}

// ─── PAGE DOSSIERS ────────────────────────────────────────────────────────────
function PageDossiers({dossiers,clients,tarifs,onVoirFacture,setDossiers,onModifier,role,t,lang}) {
  const now=new Date();
  const [moisActif,setMoisActif]=useState(now.getMonth());
  const [anneeActive,setAnneeActive]=useState(now.getFullYear());
  const moisNoms=MOIS[lang]||MOIS.fr;
  const moisDispos=[...new Set(dossiers.map(d=>{const {mois,annee}=getMoisAnnee(d.dateCreation);return annee+"-"+String(mois).padStart(2,"0")}))].sort().reverse();
  const moisActuelKey=now.getFullYear()+"-"+String(now.getMonth()).padStart(2,"0");
  if(!moisDispos.includes(moisActuelKey)) moisDispos.unshift(moisActuelKey);
  const dossiersDuMois=dossiers.filter(d=>{const {mois,annee}=getMoisAnnee(d.dateCreation);return mois===moisActif&&annee===anneeActive;});
  const caEstime=dossiersDuMois.reduce((s,d)=>s+genFacture(d,tarifs).ht,0);
  const enAttente=dossiers.filter(d=>d.statutFacture==="en_attente");
  const modifiees=dossiers.filter(d=>d.statutFacture==="modifiee");
  return (
    <div>
      {role==="comptable"&&enAttente.length>0&&<div style={{background:"#fef3c7",border:"2px solid #f59e0b",borderRadius:12,padding:"14px 18px",marginBottom:10,fontFamily:"sans-serif"}}>
        <div style={{fontWeight:700,color:"#92400e",fontSize:14,marginBottom:8}}>⏳ {enAttente.length} {t.en_attente_validation}</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>{enAttente.map(d=><button key={d.id} onClick={()=>onVoirFacture(d)} style={sf.btn("warning",{fontSize:12,padding:"5px 12px"})}>{d.client}{d.invoiceRef?" #"+d.invoiceRef:""}</button>)}</div>
      </div>}
      {role==="comptable"&&modifiees.length>0&&<div style={{background:"#fee2e2",border:"2px solid "+C.danger,borderRadius:12,padding:"14px 18px",marginBottom:10,fontFamily:"sans-serif"}}>
        <div style={{fontWeight:700,color:C.danger,fontSize:14,marginBottom:8}}>⚠️ {modifiees.length} {t.modifiees_apres}</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>{modifiees.map(d=><button key={d.id} onClick={()=>onVoirFacture(d)} style={sf.btn("danger",{fontSize:12,padding:"5px 12px"})}>{d.client}{d.invoiceRef?" #"+d.invoiceRef:""}</button>)}</div>
      </div>}
      {role==="chef"&&modifiees.length>0&&<div style={{background:"#fee2e2",border:"2px solid "+C.danger,borderRadius:12,padding:"12px 18px",marginBottom:10,fontFamily:"sans-serif",fontSize:13,fontWeight:600,color:C.danger}}>⚠️ {modifiees.length} {t.modifiees_apres}</div>}

      <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:16,flexWrap:"wrap"}}>
        {moisDispos.map(key=>{
          const [a,m]=key.split("-");const annee=parseInt(a);const mois=parseInt(m);
          const actif=mois===moisActif&&annee===anneeActive;
          const nb=dossiers.filter(d=>{const dm=getMoisAnnee(d.dateCreation);return dm.mois===mois&&dm.annee===annee;}).length;
          return <button key={key} onClick={()=>{setMoisActif(mois);setAnneeActive(annee);}} style={{padding:"8px 18px",border:"1.5px solid "+(actif?C.navy:C.border),borderRadius:20,background:actif?C.navy:C.white,color:actif?"#fff":C.grayText,fontFamily:"sans-serif",fontSize:13,cursor:"pointer",fontWeight:actif?700:500,whiteSpace:"nowrap",boxShadow:actif?"0 2px 8px rgba(12,35,64,0.15)":"none"}}>
            {moisNoms[mois]} {annee}{nb>0&&<span style={{marginLeft:6,background:actif?C.accent:C.grayMid,color:actif?C.navy:"#fff",borderRadius:10,padding:"1px 7px",fontSize:10,fontWeight:700}}>{nb}</span>}
          </button>;
        })}
      </div>

      <div style={{...sf.card,padding:0,marginBottom:16}}>
        <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)"}}>
          {[{val:dossiersDuMois.length,label:t.dossiers_nb,color:C.navy},{val:dossiersDuMois.filter(d=>d.statut==="ouvert").length,label:t.en_cours,color:"#d97706"},{val:dossiersDuMois.filter(d=>d.statut==="ouvert").reduce((s,d)=>{const e=d.mouvements.filter(m=>m.type==="entree").reduce((a,m)=>a+m.palettes,0);const so=d.mouvements.filter(m=>m.type==="sortie").reduce((a,m)=>a+m.palettes,0);return s+e-so;},0),label:t.palettes_stock,color:"#2563eb"},{val:caEstime.toFixed(0)+" €",label:t.ca_ht_mois,color:C.accent}].map((k,i)=>(
            <div key={i} style={{textAlign:"center",padding:"20px 12px",borderRight:i<3?"1px solid "+C.border:"none"}}>
              <div style={{fontSize:28,fontWeight:800,color:k.color,fontFamily:"sans-serif"}}>{k.val}</div>
              <div style={{fontSize:10,color:C.grayText,fontFamily:"sans-serif",textTransform:"uppercase",letterSpacing:"0.08em",marginTop:4,fontWeight:600}}>{k.label}</div>
            </div>
          ))}
        </div>
      </div>

      <div style={sf.card}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:8}}>
          <div style={sf.sec}>{t.tous_dossiers} — {moisNoms[moisActif]} {anneeActive}</div>
          {caEstime>0&&<div style={{fontFamily:"sans-serif",fontSize:13,color:C.grayText}}>HT : <strong style={{color:C.accent}}>{caEstime.toFixed(2)} €</strong></div>}
        </div>
        {dossiersDuMois.length===0&&<div style={{textAlign:"center",padding:"56px 0",color:C.grayText,fontFamily:"sans-serif"}}>
          <div style={{fontSize:48,marginBottom:12}}>📦</div>
          <div style={{fontSize:15,fontWeight:600,marginBottom:4}}>{t.aucun_dossier}</div>
          <div style={{fontSize:13,color:C.grayMid}}>{t.creer_premier}</div>
        </div>}
        {dossiersDuMois.map(d=>{
          const totalE=d.mouvements.filter(m=>m.type==="entree").reduce((s,m)=>s+m.palettes,0);
          const totalS=d.mouvements.filter(m=>m.type==="sortie").reduce((s,m)=>s+m.palettes,0);
          const ht=genFacture(d,tarifs).ht;
          const clientObj=clients.find(c=>c.nom===d.client);
          const sf2=d.statutFacture;
          const estV=sf2==="validee";
          const bColor=sf2==="modifiee"?C.danger:sf2==="en_attente"?"#f59e0b":sf2==="validee"?C.success:C.border;
          const bgC=sf2==="modifiee"?"#fff5f5":sf2==="en_attente"?"#fffbf0":sf2==="validee"?"#f0fdf4":C.white;
          return <div key={d.id} style={{border:"1.5px solid "+bColor,borderRadius:12,marginBottom:10,overflow:"hidden",boxShadow:"0 1px 4px rgba(12,35,64,0.06)"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 18px",background:bgC,flexWrap:"wrap",gap:10}}>
              <div style={{display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
                <div>
                  <div style={{fontWeight:700,fontSize:15,display:"flex",alignItems:"center",gap:8,flexWrap:"wrap",fontFamily:"sans-serif",color:C.navy}}>
                    {d.client}
                    {clientObj?.numero&&<span style={{fontSize:11,color:C.grayText,fontWeight:400}}>N°{clientObj.numero}</span>}
                    {d.invoiceRef&&<span style={{color:C.accent,fontSize:12,fontWeight:600}}>#{d.invoiceRef}</span>}
                    {clientObj&&!clientObj.tva&&<span style={sf.pill("#92400e","#fef9c3",{fontSize:10})}>HT</span>}
                  </div>
                  <div style={{fontSize:11,color:C.grayText,fontFamily:"sans-serif",marginTop:3}}>{d.dateCreation} · {d.mouvements.length} {t.mvt}{d.notes?" · "+d.notes:""}</div>
                </div>
                <span style={sf.pill(d.statut==="ouvert"?"#92400e":C.success,d.statut==="ouvert"?"#fef3c7":"#dcfce7")}>{d.statut==="ouvert"?t.en_cours:t.cloture}</span>
                <Badge sf2={sf2} t={t}/>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                <div style={{textAlign:"right",fontFamily:"sans-serif"}}>
                  <div style={{fontSize:11,color:C.grayText}}>↓{totalE} / ↑{totalS} / {totalE-totalS}</div>
                  <div style={{fontWeight:800,fontSize:16,color:C.navy}}>{ht.toFixed(2)} € HT</div>
                </div>
                {role==="chef"&&!estV&&sf2!=="en_attente"&&<button style={sf.btn("ghost",{padding:"6px 10px",fontSize:13})} onClick={()=>onModifier(d)}>✏️</button>}
                {role==="chef"&&!sf2&&<button style={sf.btn("primary",{padding:"6px 12px",fontSize:12})} onClick={()=>updateSF(d.id,"en_attente",setDossiers)}>📤 {t.envoyer_compta}</button>}
                {role==="chef"&&sf2==="en_attente"&&<span style={{fontFamily:"sans-serif",fontSize:12,color:"#d97706",fontWeight:600}}>⏳ {t.en_attente}</span>}
                {role==="chef"&&estV&&<button style={sf.btn("danger",{padding:"6px 10px",fontSize:12})} onClick={()=>{if(window.confirm(t.confirm_deverrouiller))onModifier(d);}}>🔓 {t.deverrouiller}</button>}
                {role==="comptable"&&sf2==="en_attente"&&<button style={sf.btn("success",{padding:"6px 12px",fontSize:12})} onClick={()=>updateSF(d.id,"validee",setDossiers)}>✅ {t.valider}</button>}
                {role==="comptable"&&sf2==="modifiee"&&<button style={sf.btn("success",{padding:"6px 12px",fontSize:12})} onClick={()=>updateSF(d.id,"validee",setDossiers)}>✅ {t.revalider}</button>}
                {role==="comptable"&&estV&&<button style={sf.btn("ghost",{padding:"6px 10px",fontSize:12})} onClick={()=>updateSF(d.id,null,setDossiers)}>🔓 {t.devalider}</button>}
                <button style={sf.btn("primary",{padding:"6px 14px",fontSize:12})} onClick={()=>onVoirFacture(d)}>{t.voir_facture}</button>
              </div>
            </div>
            <div style={{padding:"8px 18px",display:"flex",gap:6,flexWrap:"wrap",borderTop:"1px solid "+C.border,background:C.offWhite}}>
              {d.mouvements.sort((a,b)=>a.date.localeCompare(b.date)).map(m=>(
                <span key={m.id} style={sf.tag(m.type)}>{m.type==="entree"?"↓":"↑"} {m.palettes} pal.{m.poids?" · "+m.poids+"kg":""} · {m.date}{m.transporteur?" 🚛"+m.transporteur:""}{m.provenance?" · "+m.provenance:""}</span>
              ))}
            </div>
            {(d.photos||[]).length>0&&<div style={{padding:"6px 18px 10px",display:"flex",gap:6,flexWrap:"wrap",borderTop:"1px solid "+C.border,background:C.offWhite}}>
              {(d.photos||[]).map((p,i)=><img key={i} src={p.data} alt={p.name} style={{height:48,width:64,objectFit:"cover",borderRadius:6,border:"1px solid "+C.border}}/>)}
            </div>}
          </div>;
        })}
      </div>
    </div>
  );
}

// ─── PAGE FACTURE ─────────────────────────────────────────────────────────────
function PageFacture({dossier,clients,tarifs,onRetour,role,setDossiers,t}) {
  const clientObj=clients.find(c=>c.nom===dossier.client)||{tva:true};
  const avecTVA=dossier.tvaClient!==undefined?dossier.tvaClient:clientObj.tva;
  const {lignes,ht}=genFacture(dossier,tarifs);
  const tva=avecTVA?ht*0.2:0; const ttc=ht+tva;
  const sf2=dossier.statutFacture;
  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,flexWrap:"wrap",gap:10}}>
        <button style={sf.btn("ghost")} onClick={onRetour}>{t.retour}</button>
        <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"center"}}>
          <Badge sf2={sf2} t={t}/>
          {role==="comptable"&&sf2==="en_attente"&&<button style={sf.btn("success")} onClick={()=>updateSF(dossier.id,"validee",setDossiers)}>✅ {t.marquer_facture}</button>}
          {role==="comptable"&&sf2==="modifiee"&&<button style={sf.btn("success")} onClick={()=>updateSF(dossier.id,"validee",setDossiers)}>✅ {t.revalider_facture}</button>}
          {role==="comptable"&&sf2==="validee"&&<button style={sf.btn("ghost",{fontSize:12})} onClick={()=>updateSF(dossier.id,null,setDossiers)}>🔓 {t.devalider}</button>}
          <button style={sf.btn("accent")} onClick={()=>window.print()}>🖨️ {t.imprimer}</button>
        </div>
      </div>
      <div style={sf.card}>
        <div style={{background:C.navy,color:"#fff",borderRadius:10,padding:"24px 28px",display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:28,flexWrap:"wrap",gap:16}}>
          <div>
            <img src={DFDS_LOGO} alt="DFDS" style={{height:34,objectFit:"contain",marginBottom:12,}}/>
            <div style={{fontSize:18,fontWeight:800,letterSpacing:"0.02em"}}>DÉPÔT HORS DFDS</div>
            <div style={{color:"#94a3b8",fontSize:12,fontFamily:"sans-serif",marginTop:4}}>{t.zone_portuaire}</div>
          </div>
          <div style={{textAlign:"right",fontFamily:"sans-serif"}}>
            <div style={{color:C.accent,fontWeight:800,fontSize:20}}>{dossier.invoiceRef||"DOS-"+dossier.id.toString().slice(-5)}</div>
            <div style={{color:"#94a3b8",fontSize:12,marginTop:4}}>{today()}</div>
            <div style={{color:"#fff",fontSize:14,marginTop:4,fontWeight:600}}>{dossier.client}{clientObj?.numero?" · N°"+clientObj.numero:""}</div>
          </div>
        </div>
        <div style={{marginBottom:20}}>
          <div style={sf.sec}>{t.detail_mouvements}</div>
          <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>{dossier.mouvements.sort((a,b)=>a.date.localeCompare(b.date)).map(m=>(<span key={m.id} style={sf.tag(m.type)}>{m.type==="entree"?"↓":"↑"} {m.palettes} pal.{m.poids?" · "+m.poids+"kg":""} · {m.date}{m.transporteur?" 🚛"+m.transporteur:""}{m.provenance?" · "+m.provenance:""}</span>))}</div>
        </div>
        <div style={sf.sec}>{t.designation}</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontFamily:"sans-serif",fontSize:13,marginBottom:24}}>
            <thead><tr style={{background:C.offWhite}}>{[t.designation,t.qte,"PU HT",t.total_ht].map((h,i)=><th key={i} style={{padding:"10px 14px",textAlign:i===0?"left":"right",fontSize:10,textTransform:"uppercase",letterSpacing:"0.08em",color:C.grayText,borderBottom:"2px solid "+C.border,fontWeight:700}}>{h}</th>)}</tr></thead>
            <tbody>{lignes.map((l,i)=><tr key={i} style={{borderBottom:"1px solid "+C.border,background:i%2===0?C.white:C.offWhite}}><td style={{padding:"10px 14px",color:C.navy}}>{l.desc}</td><td style={{padding:"10px 14px",textAlign:"right"}}>{l.qty}</td><td style={{padding:"10px 14px",textAlign:"right"}}>{(l.pu||0).toFixed(2)} €</td><td style={{padding:"10px 14px",textAlign:"right",fontWeight:700,color:C.navy}}>{l.total.toFixed(2)} €</td></tr>)}</tbody>
          </table>
        </div>
        <div style={{display:"flex",justifyContent:"flex-end"}}>
          <div style={{width:"min(320px,100%)",fontFamily:"sans-serif"}}>
            <div style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid "+C.border,color:C.grayText,fontSize:14}}><span>{t.total_ht}</span><span>{ht.toFixed(2)} €</span></div>
            {avecTVA?<div style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid "+C.border,color:C.grayText,fontSize:14}}><span>{t.tva_20}</span><span>{tva.toFixed(2)} €</span></div>:<div style={{padding:"10px 12px",background:"#fef9c3",borderRadius:8,fontSize:12,color:"#92400e",fontWeight:600,marginBottom:6}}>⚠️ {t.client_exonere}</div>}
            <div style={{display:"flex",justifyContent:"space-between",padding:"16px 0",fontWeight:800,fontSize:20,color:C.navy}}><span>{avecTVA?t.total_ttc:t.total_ht2}</span><span style={{color:C.accent}}>{ttc.toFixed(2)} €</span></div>
          </div>
        </div>
        {dossier.notes&&<div style={{padding:"12px 16px",background:C.accentLight,borderRadius:8,fontFamily:"sans-serif",fontSize:13,borderLeft:"4px solid "+C.accent}}>📝 {dossier.notes}</div>}
      </div>
    </div>
  );
}

// ─── PAGE DASHBOARD ───────────────────────────────────────────────────────────
function PageDashboard({dossiers,clients,tarifs,t,lang}) {
  const now=new Date();
  const [annee,setAnnee]=useState(now.getFullYear());
  const [clientFiltre,setClientFiltre]=useState("Tous");
  const moisNoms=MOIS[lang]||MOIS.fr;
  const annees=[...new Set(dossiers.map(d=>getMoisAnnee(d.dateCreation).annee))].sort().reverse();
  if(!annees.includes(annee)&&annees.length>0) annees.unshift(annee);
  const df=dossiers.filter(d=>{const {annee:a}=getMoisAnnee(d.dateCreation);return a===annee&&(clientFiltre==="Tous"||d.client===clientFiltre);});
  const getHT=d=>genFacture(d,tarifs).ht;
  const caTotal=df.reduce((s,d)=>s+getHT(d),0);
  const palTotal=df.reduce((s,d)=>s+d.mouvements.filter(m=>m.type==="entree").reduce((a,m)=>a+m.palettes,0),0);
  const parMois=Array.from({length:12},(_,i)=>{const dd=df.filter(d=>getMoisAnnee(d.dateCreation).mois===i);return {mois:moisNoms[i],nb:dd.length,ca:dd.reduce((s,d)=>s+getHT(d),0),pal:dd.reduce((s,d)=>s+d.mouvements.filter(m=>m.type==="entree").reduce((a,m)=>a+m.palettes,0),0)};});
  const maxCA=Math.max(...parMois.map(m=>m.ca),1);
  const parClient={};
  df.forEach(d=>{if(!parClient[d.client])parClient[d.client]={ca:0,nb:0,pal:0};parClient[d.client].ca+=getHT(d);parClient[d.client].nb++;parClient[d.client].pal+=d.mouvements.filter(m=>m.type==="entree").reduce((a,m)=>a+m.palettes,0);});
  const topClients=Object.entries(parClient).sort((a,b)=>b[1].ca-a[1].ca);
  return (
    <div>
      <div style={{...sf.card,padding:"14px 20px",marginBottom:16}}>
        <div style={{display:"flex",gap:12,alignItems:"center",flexWrap:"wrap"}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}><label style={{...sf.lbl,margin:0}}>{t.annee}</label><select style={{...sf.sel,width:"auto"}} value={annee} onChange={e=>setAnnee(+e.target.value)}>{annees.map(a=><option key={a} value={a}>{a}</option>)}</select></div>
          <div style={{display:"flex",alignItems:"center",gap:8}}><label style={{...sf.lbl,margin:0}}>{t.client}</label><select style={{...sf.sel,width:"auto"}} value={clientFiltre} onChange={e=>setClientFiltre(e.target.value)}><option>Tous</option>{clients.map(c=><option key={c.nom} value={c.nom}>{c.nom}</option>)}</select></div>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))",gap:12,marginBottom:16}}>
        {[{val:df.length,label:t.dossiers_nb,color:C.navy},{val:caTotal.toFixed(0)+" €",label:t.ca_ht_total,color:C.accent},{val:palTotal,label:t.palettes_entrees,color:"#2563eb"},{val:df.filter(d=>d.statutFacture==="validee").length,label:t.factures_validees,color:C.success}].map((k,i)=>(
          <div key={i} style={{...sf.card,textAlign:"center",padding:"20px 12px",marginBottom:0}}>
            <div style={{fontSize:28,fontWeight:800,color:k.color,fontFamily:"sans-serif"}}>{k.val}</div>
            <div style={{fontSize:10,color:C.grayText,fontFamily:"sans-serif",textTransform:"uppercase",letterSpacing:"0.08em",marginTop:6,fontWeight:600}}>{k.label}</div>
          </div>
        ))}
      </div>
      <div style={sf.card}>
        <div style={sf.sec}>{t.ca_par_mois} — {annee}</div>
        <div style={{display:"flex",gap:4,alignItems:"flex-end",height:130,padding:"0 4px"}}>
          {parMois.map((m,i)=>(
            <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
              <div style={{fontSize:9,fontFamily:"sans-serif",color:C.accent,fontWeight:700}}>{m.ca>0?m.ca.toFixed(0):""}</div>
              <div style={{width:"100%",background:m.ca>0?C.navy:C.border,borderRadius:"4px 4px 0 0",height:Math.max(2,(m.ca/maxCA)*90)+"px",transition:"height 0.4s"}}/>
              <div style={{fontSize:8,fontFamily:"sans-serif",color:C.grayText,textAlign:"center",fontWeight:600}}>{m.mois.slice(0,3).toUpperCase()}</div>
            </div>
          ))}
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))",gap:16}}>
        <div style={sf.card}>
          <div style={sf.sec}>{t.par_client}</div>
          {topClients.length===0?<div style={{color:C.grayText,fontFamily:"sans-serif",fontSize:13,textAlign:"center",padding:16}}>{t.aucune_donnee}</div>
            :topClients.map(([nom,data])=>(<div key={nom} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid "+C.border,flexWrap:"wrap",gap:8}}><div style={{fontFamily:"sans-serif"}}><div style={{fontWeight:700,fontSize:14,color:C.navy}}>{nom}</div><div style={{fontSize:12,color:C.grayText}}>{data.nb} · {data.pal} pal.</div></div><div style={{fontWeight:800,color:C.accent,fontFamily:"sans-serif",fontSize:15}}>{data.ca.toFixed(2)} €</div></div>))}
        </div>
        <div style={sf.card}>
          <div style={sf.sec}>{t.detail_mensuel}</div>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse",fontFamily:"sans-serif",fontSize:12}}>
              <thead><tr style={{background:C.offWhite}}>{[t.mois,t.dossiers_nb,"CA HT"].map((h,i)=><th key={i} style={{padding:"8px 10px",textAlign:i===0?"left":"right",fontSize:10,textTransform:"uppercase",color:C.grayText,borderBottom:"2px solid "+C.border,fontWeight:700}}>{h}</th>)}</tr></thead>
              <tbody>{parMois.map((m,i)=>(<tr key={i} style={{borderBottom:"1px solid "+C.border,background:i%2===0?C.white:C.offWhite,opacity:m.nb===0?0.4:1}}><td style={{padding:"7px 10px",fontWeight:m.nb>0?700:400,color:C.navy}}>{m.mois.slice(0,3)}</td><td style={{padding:"7px 10px",textAlign:"right"}}>{m.nb}</td><td style={{padding:"7px 10px",textAlign:"right",fontWeight:700,color:m.ca>0?C.accent:C.grayText}}>{m.ca>0?m.ca.toFixed(0)+" €":"—"}</td></tr>))}</tbody>
              <tfoot><tr style={{background:C.navy,color:"#fff"}}><td style={{padding:"9px 10px",fontWeight:800}}>{t.total}</td><td style={{padding:"9px 10px",textAlign:"right",fontWeight:700}}>{df.length}</td><td style={{padding:"9px 10px",textAlign:"right",fontWeight:800,color:C.accent}}>{caTotal.toFixed(0)} €</td></tr></tfoot>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── PAGE EXPORT ──────────────────────────────────────────────────────────────
function PageExport({dossiers,clients,tarifs,t,lang}) {
  const now=new Date(); const moisNoms=MOIS[lang]||MOIS.fr;
  const [annee,setAnnee]=useState(now.getFullYear());
  const [mois,setMois]=useState(now.getMonth());
  const [selection,setSelection]=useState({});
  const annees=[...new Set(dossiers.map(d=>getMoisAnnee(d.dateCreation).annee))].sort().reverse();
  if(!annees.includes(annee)) annees.unshift(annee);
  const ddm=dossiers.filter(d=>{const {mois:m,annee:a}=getMoisAnnee(d.dateCreation);return m===mois&&a===annee;});
  const getHT=d=>genFacture(d,tarifs).ht;
  const toggleAll=()=>{if(Object.keys(selection).length===ddm.length)setSelection({});else{const s={};ddm.forEach(d=>s[d.id]=true);setSelection(s);}};
  const sel=ddm.filter(d=>selection[d.id]);
  const caSel=sel.reduce((s,d)=>s+getHT(d),0);
  const sfLbl={null:t.brouillon,en_attente:t.att_validation,validee:t.validee,modifiee:t.modifiee};
  const handleExport=()=>{
    const html=`<html><head><style>body{font-family:sans-serif;font-size:13px;padding:24px;color:#0C2340}h1{font-size:20px;border-bottom:3px solid #E8A020;padding-bottom:10px;color:#0C2340}h2{font-size:14px;color:#64748b;margin-top:24px;border-bottom:1px solid #e2e8f0;padding-bottom:6px}table{width:100%;border-collapse:collapse;margin-bottom:16px}th{background:#f8f9fc;padding:8px 10px;text-align:left;font-size:11px;text-transform:uppercase;border-bottom:2px solid #e2e8f0;color:#64748b}td{padding:9px 10px;border-bottom:1px solid #e2e8f0}.right{text-align:right}.bold{font-weight:700}.accent{color:#E8A020;font-weight:700}.tr{background:#0C2340;color:white}.tr td{padding:11px 10px;font-weight:700}</style></head><body>
    <h1>DFDS · Dépôt Hors DFDS — ${moisNoms[mois]} ${annee}</h1>
    <p style="color:#64748b;font-size:12px">Export: ${new Date().toLocaleDateString()} · ${sel.length} dossier(s)</p>
    <table><thead><tr><th>${t.client}</th><th>Ref</th><th>${t.statut}</th><th>${t.validation}</th><th>Pal.</th><th class="right">HT</th><th class="right">TVA</th><th class="right">Total</th></tr></thead>
    <tbody>${sel.map(d=>{const ht=getHT(d);const co=clients.find(c=>c.nom===d.client)||{tva:true};const avTV=d.tvaClient!==undefined?d.tvaClient:co.tva;const tva=avTV?ht*0.2:0;const ttc=ht+tva;return `<tr><td class="bold">${d.client}${co?.numero?" <small>N°${co.numero}</small>":""}</td><td>${d.invoiceRef||"—"}</td><td>${d.statut==="ouvert"?t.en_cours:t.cloture}</td><td>${sfLbl[d.statutFacture]||"—"}</td><td>${d.mouvements.filter(m=>m.type==="entree").reduce((s,m)=>s+m.palettes,0)}</td><td class="right accent">${ht.toFixed(2)} €</td><td class="right">${avTV?tva.toFixed(2)+" €":"HT"}</td><td class="right bold">${ttc.toFixed(2)} €</td></tr>`;}).join("")}</tbody>
    <tfoot><tr class="tr"><td colspan="5">TOTAL</td><td class="right">${caSel.toFixed(2)} €</td><td>—</td><td>—</td></tr></tfoot></table>
    ${sel.map(d=>{const {lignes,ht}=genFacture(d,tarifs);const co=clients.find(c=>c.nom===d.client)||{tva:true};const avTV=d.tvaClient!==undefined?d.tvaClient:co.tva;const tva=avTV?ht*0.2:0;return `<h2>${d.client}${d.invoiceRef?" — "+d.invoiceRef:""}</h2><table><thead><tr><th>Désignation</th><th class="right">Qté</th><th class="right">PU HT</th><th class="right">Total HT</th></tr></thead><tbody>${lignes.map(l=>`<tr><td>${l.desc}</td><td class="right">${l.qty}</td><td class="right">${(l.pu||0).toFixed(2)} €</td><td class="right bold">${l.total.toFixed(2)} €</td></tr>`).join("")}</tbody><tfoot><tr class="tr"><td colspan="2">Total HT</td><td class="right" colspan="2">${ht.toFixed(2)} €</td></tr>${avTV?`<tr class="tr"><td colspan="2">TVA 20%</td><td class="right" colspan="2">${tva.toFixed(2)} €</td></tr><tr class="tr"><td colspan="2">TOTAL TTC</td><td class="right" colspan="2">${(ht+tva).toFixed(2)} €</td></tr>`:`<tr class="tr"><td colspan="2">TOTAL HT</td><td class="right" colspan="2">${ht.toFixed(2)} €</td></tr>`}</tfoot></table>`;}).join("")}
    </body></html>`;
    const w=window.open("","_blank");w.document.write(html);w.document.close();w.print();
  };
  return (
    <div>
      <div style={sf.card}>
        <div style={sf.sec}>{t.periode}</div>
        <div style={{display:"flex",gap:12,flexWrap:"wrap",alignItems:"center"}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}><label style={{...sf.lbl,margin:0}}>{t.mois}</label><select style={{...sf.sel,width:"auto"}} value={mois} onChange={e=>setMois(+e.target.value)}>{moisNoms.map((m,i)=><option key={i} value={i}>{m}</option>)}</select></div>
          <div style={{display:"flex",alignItems:"center",gap:8}}><label style={{...sf.lbl,margin:0}}>{t.annee}</label><select style={{...sf.sel,width:"auto"}} value={annee} onChange={e=>setAnnee(+e.target.value)}>{annees.map(a=><option key={a} value={a}>{a}</option>)}</select></div>
        </div>
      </div>
      <div style={sf.card}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:10}}>
          <div style={sf.sec}>{ddm.length} {t.dossiers_nb} — {moisNoms[mois]} {annee}</div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            <button style={sf.btn("ghost",{padding:"7px 14px",fontSize:12})} onClick={toggleAll}>{Object.keys(selection).length===ddm.length?t.deselectionner:t.selectionner_tout}</button>
            <button style={sf.btn("success",{padding:"7px 14px",fontSize:12})} onClick={handleExport} disabled={sel.length===0}>📄 {t.exporter} {sel.length>0?"("+sel.length+")":""}</button>
          </div>
        </div>
        {sel.length>0&&<div style={{background:C.accentLight,border:"1px solid #f0d090",borderRadius:8,padding:"10px 16px",marginBottom:12,fontFamily:"sans-serif",fontSize:13}}>{t.selection} : <strong>{sel.length}</strong> · HT : <strong style={{color:C.accent}}>{caSel.toFixed(2)} €</strong></div>}
        {ddm.length===0?<div style={{textAlign:"center",padding:"32px 0",color:C.grayText,fontFamily:"sans-serif"}}>{t.aucun_dossier_mois}</div>
          :ddm.map(d=>{const ht=getHT(d);const co=clients.find(c=>c.nom===d.client)||{tva:true};const avTV=d.tvaClient!==undefined?d.tvaClient:co.tva;
            return <div key={d.id} onClick={()=>setSelection(s=>({...s,[d.id]:!s[d.id]}))} style={{display:"flex",alignItems:"center",gap:14,padding:"14px 16px",borderRadius:10,marginBottom:8,border:"2px solid "+(selection[d.id]?C.navy:C.border),background:selection[d.id]?"#eff6ff":C.white,cursor:"pointer",flexWrap:"wrap",transition:"all 0.15s"}}>
              <div style={{width:22,height:22,borderRadius:6,border:"2px solid "+(selection[d.id]?C.navy:C.grayMid),background:selection[d.id]?C.navy:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{selection[d.id]&&<span style={{color:"#fff",fontSize:14,lineHeight:1,fontWeight:700}}>✓</span>}</div>
              <div style={{flex:1,fontFamily:"sans-serif"}}>
                <div style={{fontWeight:700,color:C.navy,display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>{d.client}{co?.numero&&<span style={{fontSize:11,color:C.grayText,fontWeight:400}}>N°{co.numero}</span>}{d.invoiceRef&&<span style={{color:C.accent,fontWeight:600,fontSize:12}}>#{d.invoiceRef}</span>}<Badge sf2={d.statutFacture} t={t}/></div>
                <div style={{fontSize:12,color:C.grayText,marginTop:2}}>{d.dateCreation} · {d.mouvements.filter(m=>m.type==="entree").reduce((s,m)=>s+m.palettes,0)} pal.</div>
              </div>
              <div style={{textAlign:"right",fontFamily:"sans-serif"}}>
                <div style={{fontWeight:800,color:C.accent,fontSize:15}}>{ht.toFixed(2)} € HT</div>
                {avTV?<div style={{fontSize:12,color:C.grayText}}>{(ht*1.2).toFixed(2)} € TTC</div>:<span style={sf.pill("#92400e","#fef9c3",{fontSize:10})}>HT</span>}
              </div>
            </div>;
          })}
      </div>
    </div>
  );
}

// ─── PAGE CLIENTS ─────────────────────────────────────────────────────────────
function PageClients({clients,setClients,t}) {
  const [nc,setNc]=useState({nom:"",tva:true,numero:""});
  const [ed,setEd]=useState(null); const [err,setErr]=useState("");
  const add=async()=>{const nom=nc.nom.trim().toUpperCase();if(!nom){setErr(t.nom_requis);return;}if(clients.find(c=>c.nom===nom)){setErr(t.client_existe);return;}await supabase.from("clients").upsert({nom,tva:nc.tva,numero:nc.numero||""});setClients(cs=>[...cs,{nom,tva:nc.tva,numero:nc.numero||""}]);setNc({nom:"",tva:true,numero:""});setErr("");};
  const saveEd=async(old)=>{const nom=ed.nom.trim().toUpperCase();if(!nom)return;if(nom!==old&&clients.find(c=>c.nom===nom)){setErr(t.client_existe);return;}await supabase.from("clients").delete().eq("nom",old);await supabase.from("clients").upsert({nom,tva:ed.tva,numero:ed.numero||""});setClients(cs=>cs.map(c=>c.nom===old?{nom,tva:ed.tva,numero:ed.numero||""}:c));setEd(null);setErr("");};
  const del=async(nom)=>{await supabase.from("clients").delete().eq("nom",nom);setClients(cs=>cs.filter(x=>x.nom!==nom));};
  return (
    <div>
      <div style={sf.card}>
        <div style={sf.sec}>{t.ajouter_client}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:12,alignItems:"end"}}>
          <div><label style={sf.lbl}>{t.nom}</label><input style={sf.inp} placeholder="ex: LATASTE" value={nc.nom} onChange={e=>{setNc(n=>({...n,nom:e.target.value.toUpperCase()}));setErr("");}}/></div>
          <div><label style={sf.lbl}>{t.numero_client}</label><input style={sf.inp} placeholder="103371" value={nc.numero} onChange={e=>setNc(n=>({...n,numero:e.target.value}))}/></div>
          <div><label style={sf.lbl}>{t.tva} ?</label><select style={sf.sel} value={nc.tva?"oui":"non"} onChange={e=>setNc(n=>({...n,tva:e.target.value==="oui"}))}><option value="oui">✅ Oui — TTC</option><option value="non">⚠️ Non — HT</option></select></div>
          <button style={sf.btn("primary")} onClick={add}>{t.ajouter}</button>
        </div>
        {err&&<div style={{color:C.danger,fontFamily:"sans-serif",fontSize:12,marginTop:10,background:"#fee2e2",padding:"6px 10px",borderRadius:6}}>{err}</div>}
      </div>
      <div style={sf.card}>
        <div style={sf.sec}>{clients.length} {t.clients}</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontFamily:"sans-serif",fontSize:13}}>
            <thead><tr style={{background:C.offWhite}}>{[t.numero_client,t.nom,t.tva,t.facturation,t.actions].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"left",fontSize:10,textTransform:"uppercase",letterSpacing:"0.06em",color:C.grayText,borderBottom:"2px solid "+C.border,fontWeight:700}}>{h}</th>)}</tr></thead>
            <tbody>{clients.map((c,i)=>{
              const isE=ed&&ed._orig===c.nom;
              return <tr key={c.nom} style={{borderBottom:"1px solid "+C.border,background:i%2===0?C.white:C.offWhite}}>
                <td style={{padding:"10px 14px",color:C.grayText,fontSize:12,fontWeight:600}}>{isE?<input style={{...sf.inp,padding:"5px 8px",fontSize:12,width:80}} value={ed.numero||""} onChange={e=>setEd(x=>({...x,numero:e.target.value}))}/>:(c.numero||"—")}</td>
                <td style={{padding:"10px 14px"}}>{isE?<input style={{...sf.inp,padding:"5px 10px",fontSize:13}} value={ed.nom} onChange={e=>setEd(x=>({...x,nom:e.target.value.toUpperCase()}))}/>:<span style={{fontWeight:700,color:C.navy}}>{c.nom}</span>}</td>
                <td style={{padding:"10px 14px"}}>{isE?<select style={{...sf.sel,padding:"5px",fontSize:13}} value={ed.tva?"oui":"non"} onChange={e=>setEd(x=>({...x,tva:e.target.value==="oui"}))}><option value="oui">✅ Oui</option><option value="non">⚠️ Non</option></select>:<span style={sf.pill(c.tva?C.success:C.accent,c.tva?"#dcfce7":C.accentLight,{fontSize:11})}>{c.tva?"TTC":"HT"}</span>}</td>
                <td style={{padding:"10px 14px",color:C.grayText,fontSize:12}}>{(isE?ed.tva:c.tva)?t.ttc:t.ht_uniquement}</td>
                <td style={{padding:"10px 14px"}}><div style={{display:"flex",gap:6,flexWrap:"wrap"}}>{isE?<><button style={sf.btn("primary",{padding:"5px 12px",fontSize:12})} onClick={()=>saveEd(c.nom)}>✓</button><button style={sf.btn("ghost",{padding:"5px 12px",fontSize:12})} onClick={()=>setEd(null)}>✕</button></>:<><button style={sf.btn("ghost",{padding:"5px 12px",fontSize:12})} onClick={()=>setEd({nom:c.nom,tva:c.tva,numero:c.numero||"",_orig:c.nom})}>✏️</button><button style={sf.btn("danger",{padding:"5px 12px",fontSize:12})} onClick={()=>del(c.nom)}>🗑️</button></>}</div></td>
              </tr>;
            })}</tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// ─── PAGE TARIFS ──────────────────────────────────────────────────────────────
function PageTarifs({tarifs,setTarifs,t}) {
  const [editId,setEditId]=useState(null); const [editVal,setEditVal]=useState(0);
  const save=(id)=>{const u=tarifs.map(x=>x.id===id?{...x,prix:+editVal}:x);setTarifs(u);localStorage.setItem("dm_tarifs",JSON.stringify(u));setEditId(null);};
  return (
    <div style={sf.card}>
      <div style={sf.sec}>{t.grille_tarifaire}</div>
      <div style={{background:"#fef9c3",border:"1.5px solid #f59e0b",borderRadius:8,padding:"10px 14px",marginBottom:16,fontFamily:"sans-serif",fontSize:12,color:"#92400e",fontWeight:600}}>⚠️ {t.tarifs_warning}</div>
      <div style={{overflowX:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontFamily:"sans-serif",fontSize:13}}>
          <thead><tr style={{background:C.offWhite}}>{[t.grille_tarifaire,t.prix_ht,t.unite,t.action].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"left",fontSize:10,textTransform:"uppercase",color:C.grayText,borderBottom:"2px solid "+C.border,fontWeight:700}}>{h}</th>)}</tr></thead>
          <tbody>{tarifs.map((x,i)=>{const isE=editId===x.id;return <tr key={x.id} style={{borderBottom:"1px solid "+C.border,background:i%2===0?C.white:C.offWhite}}>
            <td style={{padding:"10px 14px",fontWeight:600,color:C.navy}}>{x.label||x.labelFr}</td>
            <td style={{padding:"10px 14px"}}>{isE?<input style={{...sf.inp,width:90,padding:"5px 10px",fontSize:13}} type="number" step="0.01" value={editVal} onChange={e=>setEditVal(e.target.value)}/>:<span style={{fontWeight:800,color:C.accent}}>{x.prix} €</span>}</td>
            <td style={{padding:"10px 14px",color:C.grayText,fontSize:12}}>{x.unite}</td>
            <td style={{padding:"10px 14px"}}>{isE?<div style={{display:"flex",gap:6}}><button style={sf.btn("primary",{padding:"5px 10px",fontSize:12})} onClick={()=>save(x.id)}>✓</button><button style={sf.btn("ghost",{padding:"5px 10px",fontSize:12})} onClick={()=>setEditId(null)}>✕</button></div>:<button style={sf.btn("ghost",{padding:"5px 10px",fontSize:12})} onClick={()=>{setEditId(x.id);setEditVal(x.prix);}}>✏️</button>}</td>
          </tr>;})}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ─── APP PRINCIPALE ───────────────────────────────────────────────────────────
export default function DepotManager() {
  const [role,setRole]=useState(()=>sessionStorage.getItem("dm_role")||null);
  const [lang,setLang]=useState(()=>sessionStorage.getItem("dm_lang")||"fr");
  const [tab,setTab]=useState("dossiers");
  const [factureOuverte,setFactureOuverte]=useState(null);
  const [editingDossier,setEditingDossier]=useState(null);
  const [dossiers,setDossiers]=useState([]);
  const [clients,setClients]=useState(CLIENTS_INIT);
  const [tarifs,setTarifs]=useState(()=>{try{const x=localStorage.getItem("dm_tarifs");return x?JSON.parse(x):TARIFS_DEFAUT;}catch{return TARIFS_DEFAUT;}});
  const [chargement,setChargement]=useState(true);
  const t=T[lang]||T.fr;

  const handleLogin=(r,l)=>{const dl=l||(r==="chef"?"fr":"en");sessionStorage.setItem("dm_role",r);sessionStorage.setItem("dm_lang",dl);setRole(r);setLang(dl);};
  const handleLogout=()=>{sessionStorage.removeItem("dm_role");sessionStorage.removeItem("dm_lang");setRole(null);setTab("dossiers");};
  const changeLang=(l)=>{setLang(l);sessionStorage.setItem("dm_lang",l);};

  useEffect(()=>{
    if(!role)return;
    async function charger(){
      const {data:d}=await supabase.from("dossiers").select("*");
      const {data:c}=await supabase.from("clients").select("*");
      if(d) setDossiers(d.map(x=>({...x,dateCreation:x.date_creation,invoiceRef:x.invoice_ref,fraisSupp:x.frais_supp||[],lignesSnap:x.lignes_snap||null,tvaClient:x.tva_client,statutFacture:x.statut_facture||null,photos:x.photos||[]})));
      if(c&&c.length>0) setClients(c.map(x=>({...x,numero:x.numero||""})));
      setChargement(false);
    }
    charger();
  },[role]);

  const saveDossier=async(d)=>{
    await supabase.from("dossiers").upsert({
      id:d.id,client:d.client,invoice_ref:d.invoiceRef,notes:d.notes,
      palettisation:d.palettisation,depotage:d.depotage,statut:d.statut,
      date_creation:d.dateCreation,mouvements:d.mouvements,
      frais_supp:d.fraisSupp||[],lignes_snap:d.lignesSnap||null,
      tva_client:d.tvaClient,statut_facture:d.statutFacture||null,photos:d.photos||[]
    });
    setDossiers(ds=>{const idx=ds.findIndex(x=>x.id===d.id);if(idx>=0){const n=[...ds];n[idx]=d;return n;}return [d,...ds];});
    setEditingDossier(null); setTab("dossiers");
  };
  const handleModifier=(d)=>{setEditingDossier(d);setTab("modifier");};

  if(!role) return <PageLogin onLogin={handleLogin}/>;

  const TABS_CHEF=[{id:"dossiers",label:t.dossiers},{id:"nouveau",label:t.nouveau},{id:"dashboard",label:t.stats},{id:"export",label:t.export},{id:"clients",label:t.clients},{id:"tarifs",label:t.tarifs}];
  const TABS_COMPTA=[{id:"dossiers",label:t.dossiers},{id:"dashboard",label:t.stats},{id:"export",label:t.export}];
  const TABS=role==="chef"?TABS_CHEF:TABS_COMPTA;
  const nbA=dossiers.filter(d=>d.statutFacture==="en_attente"||d.statutFacture==="modifiee").length;

  if(chargement) return (
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100vh",background:C.navy,flexDirection:"column",gap:16}}>
      <img src={DFDS_LOGO} alt="DFDS" style={{height:48,objectFit:"contain",}}/>
      <div style={{fontFamily:"sans-serif",color:"rgba(255,255,255,0.5)",fontSize:14,letterSpacing:"0.05em"}}>Chargement…</div>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:C.offWhite,color:C.navy}}>
      <style>{`
        * { box-sizing: border-box; }
        .sidebar { display: flex; }
        .main-content { margin-left: 220px; }
        .mobile-nav { display: none; }
        .hide-mobile { display: block; }
        @media (max-width: 768px) {
          .sidebar { display: none !important; }
          .main-content { margin-left: 0 !important; padding: 12px !important; padding-bottom: 80px !important; }
          .mobile-nav { display: flex !important; }
          .hide-mobile { display: none !important; }
          .header-role { display: none; }
          .lang-btn span { font-size: 9px !important; padding: 2px 5px !important; }
          .logout-btn { font-size: 10px !important; padding: 3px 6px !important; }
        }
      `}</style>

      {/* HEADER */}
      <header style={{background:C.navy,color:"#fff",padding:"0 16px",display:"flex",alignItems:"center",justifyContent:"space-between",height:52,position:"fixed",top:0,left:0,right:0,zIndex:300,boxShadow:"0 2px 16px rgba(12,35,64,0.3)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,minWidth:0,overflow:"hidden"}}>
          <img src={DFDS_LOGO} alt="DFDS" style={{height:24,objectFit:"contain",flexShrink:0}}/>
          <div style={{width:1,height:20,background:"rgba(255,255,255,0.2)",flexShrink:0}}/>
          <div style={{minWidth:0}}>
            <div style={{fontSize:11,fontWeight:700,color:"#fff",textTransform:"uppercase",fontFamily:"sans-serif",whiteSpace:"nowrap"}}>Depot Manager</div>
            <div className="header-role" style={{fontSize:8,color:C.accent,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:600,whiteSpace:"nowrap"}}>{role==="chef"?t.chef_quai:t.comptable}</div>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}>
          <div style={{display:"flex",gap:2}}>
            {["fr","en","tr"].map(l=><button key={l} onClick={()=>changeLang(l)} style={{background:lang===l?C.accent:"rgba(255,255,255,0.1)",border:"none",color:lang===l?C.navy:"rgba(255,255,255,0.7)",cursor:"pointer",padding:"3px 7px",borderRadius:4,fontSize:10,fontWeight:700,fontFamily:"sans-serif"}}>{l.toUpperCase()}</button>)}
          </div>
          {role==="comptable"&&nbA>0&&<div style={{background:C.danger,color:"#fff",borderRadius:20,padding:"1px 6px",fontSize:10,fontFamily:"sans-serif",fontWeight:800}}>🔔{nbA}</div>}
          <div style={{width:6,height:6,borderRadius:"50%",background:"#00d97e",flexShrink:0}}/>
          <button onClick={handleLogout} style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.2)",color:"#fff",cursor:"pointer",fontSize:10,padding:"4px 8px",borderRadius:4,fontFamily:"sans-serif",fontWeight:600,whiteSpace:"nowrap"}}>{t.deconnexion}</button>
        </div>
      </header>

      <div style={{display:"flex",paddingTop:52}}>

        {/* SIDEBAR DESKTOP */}
        <aside className="sidebar" style={{width:220,height:"calc(100vh - 52px)",background:C.navy,position:"fixed",top:52,left:0,bottom:0,zIndex:200,flexDirection:"column",padding:"12px 0",overflowY:"auto"}}>
          {TABS.map(tb=>{
            const icons={"dossiers":"📁","nouveau":"➕","dashboard":"📊","export":"📄","clients":"👥","tarifs":"💶"};
            const active=tab===tb.id||(tab==="facture"&&tb.id==="dossiers")||(tab==="modifier"&&tb.id==="nouveau");
            return <button key={tb.id} onClick={()=>setTab(tb.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 20px",border:"none",background:active?"rgba(232,160,32,0.15)":"transparent",color:active?C.accent:"rgba(255,255,255,0.55)",cursor:"pointer",fontSize:13,fontFamily:"sans-serif",fontWeight:active?700:400,borderLeft:active?"3px solid "+C.accent:"3px solid transparent",textAlign:"left",width:"100%",transition:"all 0.15s"}}>
              <span style={{fontSize:15,flexShrink:0}}>{icons[tb.id]}</span>
              <span>{tb.label}</span>
            </button>;
          })}
          <div style={{marginTop:"auto",padding:"16px 20px",borderTop:"1px solid rgba(255,255,255,0.08)"}}>
            <div style={{fontSize:10,color:"rgba(255,255,255,0.3)",fontFamily:"sans-serif"}}>DFDS · Sète · 2026</div>
          </div>
        </aside>

        {/* MAIN CONTENT */}
        <main className="main-content" style={{flex:1,marginLeft:220,padding:"20px",minHeight:"calc(100vh - 52px)",width:"100%"}}>
          {tab==="dossiers"&&<PageDossiers dossiers={dossiers} clients={clients} tarifs={tarifs} role={role} lang={lang} t={t} onVoirFacture={d=>{setFactureOuverte(d);setTab("facture");}} setDossiers={setDossiers} onModifier={handleModifier}/>}
          {tab==="nouveau"&&role==="chef"&&<FormDossier clients={clients} tarifs={tarifs} onSave={saveDossier} t={t}/>}
          {tab==="modifier"&&editingDossier&&<FormDossier clients={clients} tarifs={tarifs} dossierInitial={editingDossier} onSave={saveDossier} onCancel={()=>setTab("dossiers")} t={t}/>}
          {tab==="dashboard"&&<PageDashboard dossiers={dossiers} clients={clients} tarifs={tarifs} t={t} lang={lang}/>}
          {tab==="export"&&<PageExport dossiers={dossiers} clients={clients} tarifs={tarifs} t={t} lang={lang}/>}
          {tab==="clients"&&role==="chef"&&<PageClients clients={clients} setClients={setClients} t={t}/>}
          {tab==="tarifs"&&role==="chef"&&<PageTarifs tarifs={tarifs} setTarifs={setTarifs} t={t}/>}
          {tab==="facture"&&factureOuverte&&<PageFacture dossier={factureOuverte} clients={clients} tarifs={tarifs} role={role} setDossiers={setDossiers} onRetour={()=>setTab("dossiers")} t={t}/>}
        </main>
      </div>

      {/* BARRE MOBILE BAS */}
      <nav className="mobile-nav" style={{display:"none",position:"fixed",bottom:0,left:0,right:0,background:C.navy,borderTop:"1px solid rgba(255,255,255,0.1)",zIndex:300,paddingBottom:"env(safe-area-inset-bottom)"}}>
        {TABS.slice(0,role==="chef"?6:3).map(tb=>{
          const icons={"dossiers":"📁","nouveau":"➕","dashboard":"📊","export":"📄","clients":"👥","tarifs":"💶"};
          const active=tab===tb.id||(tab==="facture"&&tb.id==="dossiers")||(tab==="modifier"&&tb.id==="nouveau");
          const shortLabels={"dossiers":"Dossiers","nouveau":"Nouveau","dashboard":"Stats","export":"Export","clients":"Clients","tarifs":"Tarifs"};
          return <button key={tb.id} onClick={()=>setTab(tb.id)} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:1,padding:"6px 2px 8px",border:"none",background:"transparent",color:active?C.accent:"rgba(255,255,255,0.45)",cursor:"pointer",fontFamily:"sans-serif",fontSize:9,fontWeight:active?700:400}}>
            <span style={{fontSize:18}}>{icons[tb.id]}</span>
            <span>{shortLabels[tb.id]}</span>
          </button>;
        })}
      </nav>
    </div>
  );
}

